#define REC_LENGTH 49
#define REC_WINDOW 10
#define LATITUDE_POS 28
#define OPEN 10000.0f

typedef struct {
    char entry[REC_LENGTH];
    float dist;
} cl_neighbor;

// Helper function to parse float from string in OpenCL
float parse_float(const char *str) {
    float val = 0.0f;
    float frac = 0.0f;
    float divisor = 1.0f;
    int sign = 1;
    int i = 0;
    char c = str[i];

    // Skip spaces
    while (c == ' ' || c == '\t') {
        i++;
        c = str[i];
    }

    // Sign
    if (c == '-') {
        sign = -1;
        i++;
        c = str[i];
    } else if (c == '+') {
        i++;
        c = str[i];
    }

    // Integer part
    while (c >= '0' && c <= '9') {
        val = val * 10.0f + (c - '0');
        i++;
        c = str[i];
    }

    // Fractional part
    if (c == '.') {
        i++;
        c = str[i];
        while (c >= '0' && c <= '9') {
            frac = frac * 10.0f + (c - '0');
            divisor *= 10.0f;
            i++;
            c = str[i];
        }
    }

    return sign * (val + frac / divisor);
}

__kernel void compute_distances_kernel(
    const char *sandbox,
    float *z,
    int rec_count,
    float target_lat,
    float target_long)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    int base_idx = i * REC_LENGTH;
    int lat_idx = base_idx + (LATITUDE_POS - 1);

    const char *lat_str = sandbox + lat_idx;
    const char *lon_str = lat_str + 5;

    float tmp_lat = parse_float(lat_str);
    float tmp_long = parse_float(lon_str);

    float diff_lat = tmp_lat - target_lat;
    float diff_long = tmp_long - target_long;

    z[i] = sqrt(diff_lat * diff_lat + diff_long * diff_long);
}

__kernel void update_neighbors_kernel(
    const char *sandbox,
    const float *z,
    cl_neighbor *neighbors,
    int rec_count,
    int k)
{
    int i = get_global_id(0);
    if (i >= rec_count) return;

    float current_dist = z[i];

    // Find the neighbor with the maximum distance (the one to replace)
    float max_dist = -1.0f;
    int max_idx = 0;

    for (int j = 0; j < k; j++) {
        if (neighbors[j].dist > max_dist) {
            max_dist = neighbors[j].dist;
            max_idx = j;
        }
    }

    // If current record is closer than the farthest neighbor, replace it
    if (current_dist < max_dist) {
        // Copy the record string
        for (int c = 0; c < REC_LENGTH; c++) {
            neighbors[max_idx].entry[c] = sandbox[i * REC_LENGTH + c];
        }
        neighbors[max_idx].dist = current_dist;
    }
}
